+fn handle_migrate_rollback(
+    db_path: &Path,
+    backup_dir: Option<&Path>,
+    force: bool,
+) -> CliResult<()> {
+    let backups = list_db_backups(db_path, backup_dir)?;
+    if backups.is_empty() {
+        return Err(CliError::Other(format!(
