+fn storage_root_permissions_hint(path: &Path) -> String {
+    #[cfg(unix)]
+    {
+        use std::os::unix::fs::PermissionsExt;
+        std::fs::metadata(path)
+            .map(|meta| format!("{:04o}", meta.permissions().mode() & 0o7777))
+            .unwrap_or_else(|_| "unknown".to_string())
+    }
+    #[cfg(not(unix))]
+    {
+        "unknown".to_string()
+    }
+}
